const transitionInitiativeStatus = `-- name: TransitionInitiativeStatus :one
UPDATE initiative SET
    status = $2,
    pause_prev_status = $3,
    pause_reason = $4,
    needs_human_reason = $5,
    updated_at = now()
WHERE id = $1 AND status = ANY($6::text[])
RETURNING id, workspace_id, title, idea, constraints, status, autonomy_level, plan_version, orchestrator_agent_id, budget_limit_tokens, budget_spent_tokens, max_parallel_tasks, max_attempts, stall_timeout_seconds, external_wait_timeout_seconds, pause_prev_status, pause_reason, needs_human_reason, created_by, approved_by, approved_at, created_at, updated_at
`

type TransitionInitiativeStatusParams struct {
	ID               pgtype.UUID `json:"id"`
	Status           string      `json:"status"`
	PausePrevStatus  pgtype.Text `json:"pause_prev_status"`
	PauseReason      pgtype.Text `json:"pause_reason"`
	NeedsHumanReason pgtype.Text `json:"needs_human_reason"`
	FromStatuses     []string    `json:"from_statuses"`
}

// CAS transition: succeeds only when the row is still in one of the expected
// from-statuses; pgx.ErrNoRows signals a lost race (callers map it to 409 or
// retry on the next reconcile pass). The pause/needs_human bookkeeping columns
// are SET (not COALESCEd) so leaving those states clears them.
func (q *Queries) TransitionInitiativeStatus(ctx context.Context, arg TransitionInitiativeStatusParams) (Initiative, error) {
	row := q.db.QueryRow(ctx, transitionInitiativeStatus,
		arg.ID,
		arg.Status,
		arg.PausePrevStatus,
		arg.PauseReason,
		arg.NeedsHumanReason,
		arg.FromStatuses,
	)
	var i Initiative
	err := row.Scan(
		&i.ID,
		&i.WorkspaceID,
		&i.Title,
		&i.Idea,
		&i.Constraints,
		&i.Status,
		&i.AutonomyLevel,
		&i.PlanVersion,
		&i.OrchestratorAgentID,
		&i.BudgetLimitTokens,
		&i.BudgetSpentTokens,
		&i.MaxParallelTasks,
		&i.MaxAttempts,
		&i.StallTimeoutSeconds,
		&i.ExternalWaitTimeoutSeconds,
		&i.PausePrevStatus,
		&i.PauseReason,
		&i.NeedsHumanReason,
		&i.CreatedBy,
		&i.ApprovedBy,
		&i.ApprovedAt,
		&i.CreatedAt,
		&i.UpdatedAt,
	)
	return i, err
}

